import React, { createContext, useState, useRef, useContext, useEffect } from 'react';
import axios from 'axios';

const MusicContext = createContext();

export const MusicProvider = ({ children }) => {
  const [songs, setSongs] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentSong, setCurrentSong] = useState(null);
  const [favorites, setFavorites] = useState([]);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);

  const audioRef = useRef(null);
  const user = JSON.parse(localStorage.getItem('user'));

  // Lấy danh sách yêu thích
  const fetchFavorites = async () => {
    if (!user) return;
    try {
      const userId = user._id || user.id;
      const res = await axios.get(`http://localhost:5000/api/auth/${userId}/favorites`);
      // Chuyển về mảng ID string để dễ so sánh
      setFavorites(res.data.map(song => String(song._id)));
    } catch (err) { console.error("Lỗi lấy favorites:", err); }
  };

  useEffect(() => { fetchFavorites(); }, []);

  useEffect(() => {
    if (currentSong && isPlaying) {
      audioRef.current.play().catch(() => setIsPlaying(false));
    }
  }, [currentSong]);

  const playMusic = (songList, index) => {
    setSongs(songList);
    setCurrentIndex(index);
    setCurrentSong(songList[index]);
    setIsPlaying(true);
  };

  const togglePlay = () => {
    if (!currentSong) return;
    isPlaying ? audioRef.current.pause() : audioRef.current.play();
    setIsPlaying(!isPlaying);
  };

  const handleNext = () => {
    if (songs.length === 0) return;
    const nextIndex = (currentIndex + 1) % songs.length;
    setCurrentIndex(nextIndex);
    setCurrentSong(songs[nextIndex]);
    setIsPlaying(true);
  };

  const handlePrev = () => {
    if (songs.length === 0) return;
    const prevIndex = (currentIndex - 1 + songs.length) % songs.length;
    setCurrentIndex(prevIndex);
    setCurrentSong(songs[prevIndex]);
    setIsPlaying(true);
  };

  const toggleLike = async (songId) => {
    if (!user) return alert("Vui lòng đăng nhập!");
    try {
      const userId = user._id || user.id;
      const res = await axios.post('http://localhost:5000/api/auth/toggle-favorite', { userId, songId });
      setFavorites(res.data.favorites.map(id => String(id)));
    } catch (err) { console.error(err); }
  };

  const onTimeUpdate = () => setCurrentTime(audioRef.current.currentTime);
  const onLoadedMetadata = () => setDuration(audioRef.current.duration);
  const seekTo = (percent) => {
    const time = (percent / 100) * audioRef.current.duration;
    audioRef.current.currentTime = time;
  };

  return (
    <MusicContext.Provider value={{ 
      songs, currentSong, isPlaying, favorites, currentTime, duration,
      playMusic, togglePlay, handleNext, handlePrev, toggleLike, seekTo 
    }}>
      {children}
      {currentSong && (
        <audio
          ref={audioRef}
          src={encodeURI(`http://localhost:5000${currentSong.songUrl || currentSong.musicUrl}`)}
          onTimeUpdate={onTimeUpdate}
          onLoadedMetadata={onLoadedMetadata}
          onEnded={handleNext}
        />
      )}
    </MusicContext.Provider>
  );
};

export const useMusic = () => useContext(MusicContext);
